bool is_rotation(const vector<long long>& B, const vector<long long>& T, int k) {
    if (k == 0) return true;
    if (k == 1) return B[0] == T[0];

    // Iterate through all k possible shifts p (0 to k-1)
    for (int p = 0; p < k; ++p) {
        bool match = true;
        for (int j = 0; j < k; ++j) {
            // T[j] must match the element of B shifted by p: B[(j + p) % k]
            if (T[j] != B[(j + p) % k]) {
                match = false;
                break;
            }
        }
        if (match) {
            return true;
        }
    }
    return false;
}

